import React, { useState, useEffect } from 'react';
import ProductTypeForm from './ProductTypeForm';
import { getProductTypes, deleteProductType, ProductType } from '../services/api';

const filterOptions = ['Active Product Types', 'All Product Types'];
const allColumns = [
  { field: 'display_name', label: 'Display Name' },
  { field: 'api_name', label: 'API Name' },
  { field: 'asset_type', label: 'Asset Type' },
  { field: 'asset_category_type', label: 'Asset Category' },
  { field: 'description', label: 'Description' },
];

const ProductTypeTable: React.FC = () => {
  const [productTypes, setProductTypes] = useState<ProductType[]>([]);
  const [open, setOpen] = useState<boolean>(false);
  const [editing, setEditing] = useState<ProductType | null>(null);
  const [activeFilter, setActiveFilter] = useState<string>(filterOptions[0]);
  const [actionAnchorEl, setActionAnchorEl] = useState<HTMLElement | null>(null);
  const [actionRow, setActionRow] = useState<ProductType | null>(null);
  const [columnsAnchorEl, setColumnsAnchorEl] = useState<HTMLElement | null>(null);
  const [visibleColumns, setVisibleColumns] = useState<string[]>([
    'display_name',
    'api_name',
    'asset_type',
    'asset_category_type',
    'description',
  ]);
  const [currentPage, setCurrentPage] = useState<number>(1);
  const [pageSize, setPageSize] = useState<number>(10);
  const [loading, setLoading] = useState<boolean>(false);
  const [saving, setSaving] = useState<boolean>(false);

  useEffect(() => {
    fetchProductTypes();
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (columnsAnchorEl && !columnsAnchorEl.contains(event.target as Node)) {
        const dropdown = document.querySelector('[data-columns-dropdown]');
        if (dropdown && !dropdown.contains(event.target as Node)) {
          setColumnsAnchorEl(null);
        }
      }
      
      if (actionAnchorEl && !actionAnchorEl.contains(event.target as Node)) {
        const actionMenu = document.querySelector('[data-action-menu]');
        if (actionMenu && !actionMenu.contains(event.target as Node)) {
          setActionAnchorEl(null);
        }
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [columnsAnchorEl, actionAnchorEl]);

  const fetchProductTypes = async () => {
    setLoading(true);
    try {
      const response = await getProductTypes();
      setProductTypes(response.data);
    } catch (error) {
      console.error('Error fetching product types:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleOpen = (item: ProductType | null = null) => {
    setEditing(item);
    setOpen(true);
  };

  const handleClose = () => {
    setOpen(false);
    setEditing(null);
  };

  const handleSave = async () => {
    setSaving(true);
    await fetchProductTypes();
    setSaving(false);
    setOpen(false);
    setEditing(null);
  };

  const handleDelete = async (id: string) => {
    if (window.confirm('Are you sure you want to delete this product type?')) {
      try {
        await deleteProductType(id);
        fetchProductTypes();
      } catch (error) {
        console.error('Error deleting product type:', error);
      }
    }
  };

  const handleClearFilters = () => {
    setActiveFilter(filterOptions[0]);
  };

  const getParentProductTypeDisplay = (item: ProductType, visited: Set<string> = new Set()): string => {
    if (!item.parent_product_type) {
      return item.display_name;
    }

    const parentValue = item.parent_product_type;
    let parent: ProductType | null = null;

    if (typeof parentValue === 'object' && parentValue !== null) {
      parent = parentValue as ProductType;
    } else {
      parent = productTypes.find((pt) => {
        const parentId = pt.id?.toString();
        const parentDisplay = pt.display_name;
        const valueString = parentValue?.toString();
        return parentId === valueString || parentDisplay === parentValue;
      }) || null;
    }

    if (!parent) {
      return item.display_name;
    }

    const parentIdKey = parent.id?.toString() || parent.display_name;
    if (visited.has(parentIdKey)) {
      return `${parent.display_name} >> ${item.display_name}`;
    }

    visited.add(parentIdKey);
    const parentDisplay = getParentProductTypeDisplay(parent, visited);
    return `${parentDisplay} >> ${item.display_name}`;
  };

  const totalPages = Math.ceil(productTypes.length / pageSize);
  const startIndex = (currentPage - 1) * pageSize;
  const endIndex = startIndex + pageSize;
  const paginatedData = productTypes.slice(startIndex, endIndex);

  const handlePageChange = (page: number) => {
    if (page >= 1 && page <= totalPages) {
      setCurrentPage(page);
    }
  };

  const handlePageSizeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setPageSize(parseInt(e.target.value));
    setCurrentPage(1);
  };

  return (
    <div className="bg-white rounded-lg shadow-sm p-6">
      <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4 mb-4">
        <div className="flex flex-col md:flex-row md:items-center gap-3">
          <select
            value={activeFilter}
            onChange={(e) => setActiveFilter(e.target.value)}
            className="w-full md:w-64 rounded-md border border-gray-300 bg-white px-3 py-2 text-sm focus:border-blue-500 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            {filterOptions.map((option) => (
              <option key={option} value={option}>
                {option}
              </option>
            ))}
          </select>
          <button
            onClick={() => handleOpen()}
            className="rounded-md bg-blue-600 px-4 py-2 text-sm font-medium text-white hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            New
          </button>
        </div>

        <div className="flex flex-wrap items-center gap-2">
          <button
            onClick={handleClearFilters}
            className="rounded-md border border-gray-300 bg-white px-4 py-2 text-sm text-gray-700 hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            Clear All Filters
          </button>
          <div className="relative">
            <button
              onClick={(e) => setColumnsAnchorEl(e.currentTarget)}
              className="rounded-md border border-gray-300 bg-white px-4 py-2 text-sm text-gray-700 hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              ▶ Select Columns
            </button>
            {columnsAnchorEl && (
              <div className="absolute right-0 z-10 mt-1 w-56 rounded-md border border-gray-300 bg-white p-2 shadow-lg" data-columns-dropdown>
                {allColumns.map((column) => (
                  <label key={column.field} className="flex cursor-pointer items-center gap-2 rounded-sm px-2 py-1 hover:bg-gray-100">
                    <input
                      type="checkbox"
                      checked={visibleColumns.includes(column.field)}
                      onChange={() => {
                        setVisibleColumns((prev) =>
                          prev.includes(column.field)
                            ? prev.filter((value) => value !== column.field)
                            : [...prev, column.field]
                        );
                      }}
                      className="h-4 w-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                    />
                    <span className="text-sm text-gray-700">{column.label}</span>
                  </label>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>

      {loading && (
        <div className="flex justify-center items-center py-8">
          <span className="animate-spin rounded-full h-8 w-8 border-t-2 border-b-2 border-blue-600"></span>
        </div>
      )}
      <div className="bg-white rounded-lg shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th className="w-14 px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider"></th>
                {visibleColumns.includes('id') && (
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    id
                  </th>
                )}
                {visibleColumns.includes('display_name') && (
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Display Name
                  </th>
                )}
                {visibleColumns.includes('api_name') && (
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    API Name
                  </th>
                )}
                {visibleColumns.includes('asset_type') && (
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Asset Type
                  </th>
                )}
                {visibleColumns.includes('asset_category_type') && (
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Asset Category
                  </th>
                )}
                {visibleColumns.includes('description') && (
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Description
                  </th>
                )}
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {paginatedData.map((item) => (
                <tr key={item.id} className="hover:bg-gray-50">
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                    <button
                      onClick={(event) => {
                        event.stopPropagation();
                        setActionRow(item);
                        setActionAnchorEl(event.currentTarget);
                      }}
                      className="text-gray-400 hover:text-gray-600"
                      aria-label="Actions"
                    >
                      <span style={{ display: 'inline-block', lineHeight: 0 }}>
                        <svg width="20" height="20" viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg">
                          <rect y="4" width="20" height="2" rx="1" fill="currentColor"/>
                          <rect y="9" width="20" height="2" rx="1" fill="currentColor"/>
                          <rect y="14" width="20" height="2" rx="1" fill="currentColor"/>
                        </svg>
                      </span>
                    </button>
                  </td>
                  {visibleColumns.includes('id') && <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.id}</td>}
                  {visibleColumns.includes('display_name') && <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{getParentProductTypeDisplay(item)}</td>}
                  {visibleColumns.includes('api_name') && <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.api_name}</td>}
                  {visibleColumns.includes('asset_type') && <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.asset_type}</td>}
                  {visibleColumns.includes('asset_category_type') && <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.asset_category_type}</td>}
                  {visibleColumns.includes('description') && <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.description}</td>}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      <div className="bg-white rounded-lg shadow-sm p-4 mt-6 flex flex-col md:flex-row md:items-center md:justify-between">
        <div className="flex items-center space-x-2 mb-4 md:mb-0">
          <label className="text-sm text-gray-700">Page Size:</label>
          <select
            value={pageSize}
            onChange={handlePageSizeChange}
            className="px-3 py-1 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <option value={10}>10</option>
            <option value={25}>25</option>
            <option value={50}>50</option>
          </select>
        </div>

        <div className="flex items-center space-x-4">
          <span className="text-sm text-gray-700">
            {productTypes.length === 0 ? '0 to 0 of 0' : `${startIndex + 1} to ${Math.min(endIndex, productTypes.length)} of ${productTypes.length}`}
          </span>

          <div className="flex items-center space-x-2">
            <button
              onClick={() => handlePageChange(currentPage - 1)}
              disabled={currentPage === 1}
              className="px-3 py-1 border border-gray-300 rounded-md text-gray-700 hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              ← Prev
            </button>

            <span className="text-sm text-gray-700">
              Page {currentPage} of {totalPages === 0 ? 1 : totalPages}
            </span>

            <button
              onClick={() => handlePageChange(currentPage + 1)}
              disabled={currentPage === totalPages}
              className="px-3 py-1 border border-gray-300 rounded-md text-gray-700 hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              Next →
            </button>
          </div>
        </div>
      </div>

      {actionAnchorEl && (
        <div 
          className="fixed z-10 bg-white border border-gray-300 rounded-md shadow-lg" 
          data-action-menu
          style={{
            top: actionAnchorEl ? actionAnchorEl.getBoundingClientRect().bottom + window.scrollY : 0,
            left: actionAnchorEl ? actionAnchorEl.getBoundingClientRect().left + window.scrollX : 0,
          }}
        >
          <button
            onClick={() => {
              if (actionRow) handleOpen(actionRow);
              setActionAnchorEl(null);
            }}
            className="block w-full px-4 py-2 text-left text-sm text-gray-700 hover:bg-gray-100"
          >
            Edit
          </button>
          <button
            onClick={() => {
              if (actionRow) handleDelete(actionRow.id);
              setActionAnchorEl(null);
            }}
            className="block w-full px-4 py-2 text-left text-sm text-gray-700 hover:bg-gray-100"
          >
            Delete
          </button>
        </div>
      )}

      {open && (
        <div className="fixed inset-0 z-50 overflow-y-auto">
          <div className="flex min-h-screen items-center justify-center p-4 text-center">
            <div className="fixed inset-0 bg-gray-500 opacity-50" aria-hidden="true" onClick={handleClose}></div>
            <div className="z-10 w-full max-w-3xl transform overflow-hidden rounded-2xl bg-white p-6 shadow-xl transition-all">
              <div className="mb-4 flex items-center justify-between">
                <h3 className="text-xl font-semibold text-gray-900">
                  {editing ? 'Edit Product Type' : 'Add Product Type'}
                </h3>
                <button onClick={handleClose} className="rounded-full bg-gray-100 p-2 text-gray-600 hover:bg-gray-200">
                  ×
                </button>
              </div>
              <ProductTypeForm
                editing={editing}
                onSave={handleSave}
                onClose={handleClose}
                productTypes={productTypes}
                saving={saving}
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ProductTypeTable;
